define(['core/ajax'], function(Ajax) {
var blockInstanceId = 0;
var courseId        = 0;
var conversationId  = 0;
var isLoading       = false;
var strings         = {};
var attachedFileName    = '';
var attachedFileContent = '';
var init = function(config) {
blockInstanceId = config.blockinstanceid;
courseId        = config.courseid;
conversationId  = config.conversationid;
strings         = config.strings || {};
if (conversationId > 0) {
loadConversation(conversationId);
}
loadQuotaStatus();
setupEventListeners();
};
var setupEventListeners = function() {
on('mistralagent-send',         'click',  sendMessage);
on('mistralagent-newconv-btn',  'click',  startNewConversation);
on('mistralagent-file-input',   'change', handleFileSelect);
on('mistralagent-file-remove',  'click',  removeFile);
on('mistralagent-paste-btn',    'click',  openPasteModal);
on('mistralagent-modal-close',  'click',  closePasteModal);
on('mistralagent-modal-cancel', 'click',  closePasteModal);
on('mistralagent-modal-confirm','click',  confirmPastedText);
on('mistralagent-banner-btn',   'click',  toggleAgentBanner);
var input = el('mistralagent-input');
if (input) {
input.addEventListener('keydown', function(e) {
if (e.key === 'Enter' && !e.shiftKey) {
e.preventDefault();
sendMessage();
}
});
}
document.querySelectorAll('.mistralagent-conv-item').forEach(function(item) {
item.addEventListener('click', function() {
switchConversation(parseInt(item.dataset.convid, 10));
});
item.addEventListener('keydown', function(e) {
if (e.key === 'Enter' || e.key === ' ') {
e.preventDefault();
switchConversation(parseInt(item.dataset.convid, 10));
}
});
});
};
var loadConversation = function(convId) {
return ajaxCall('block_mistralagent_get_conversation', {
blockinstanceid: blockInstanceId,
courseid:        courseId,
conversationid:  convId || 0,
}).then(function(response) {
if (response.success) {
var container = el('mistralagent-messages');
if (container) { container.innerHTML = ''; }
(response.messages || []).forEach(function(msg) {
addMessageToDisplay(msg.role, msg.content);
});
}
}).catch(function(err) {
window.console.error('[MistralAgent] loadConversation error:', err);
});
};
var loadQuotaStatus = function() {
ajaxCall('block_mistralagent_get_quota_status', {
blockinstanceid: blockInstanceId,
courseid:        courseId,
}).then(function(quota) {
updateQuotaDisplay(quota);
}).catch(function() {});
};
var switchConversation = function(convId) {
if (convId === conversationId) { return; }
conversationId = convId;
document.querySelectorAll('.mistralagent-conv-item').forEach(function(i) {
i.classList.toggle('active', parseInt(i.dataset.convid, 10) === convId);
});
var container = el('mistralagent-messages');
if (container) { container.innerHTML = ''; }
loadConversation(convId);
};
var sendMessage = function() {
if (isLoading) { return; }
var input   = el('mistralagent-input');
var message = input ? input.value.trim() : '';
if (!message && !attachedFileContent) { return; }
if (attachedFileName && !attachedFileContent) {
alert(strings.filenotready || '');
return;
}
var currentFileName    = attachedFileName;
var currentFileContent = attachedFileContent;
var displayMessage     = message || (strings.analysisprefix || '…') + ' ' + currentFileName;
isLoading = true;
if (input) { input.value = ''; input.disabled = true; }
setButtonDisabled('mistralagent-send', true);
addMessageToDisplay('user', displayMessage, currentFileName);
removeFile();
showTypingIndicator();
var args = {
blockinstanceid: blockInstanceId,
courseid:        courseId,
message:         message,
conversationid:  conversationId,
};
if (currentFileContent) {
args.filecontent = currentFileContent;
args.filename    = currentFileName;
}
ajaxCall('block_mistralagent_send_message', args)
.then(function(response) {
hideTypingIndicator();
if (response.success) {
if (response.conversationid && response.conversationid !== conversationId) {
conversationId = response.conversationid;
var newUrl = new URL(window.location.href);
newUrl.searchParams.set('convid', conversationId);
history.pushState({convid: conversationId}, '', newUrl.toString());
}
addMessageToDisplay('assistant', response.response, null, response.images || []);
updateQuotaDisplay(response.quota);
} else {
showError(response.error || '');
}
})
.catch(function(error) {
hideTypingIndicator();
window.console.error('[MistralAgent] send_message error:', error);
showError(buildFriendlyError(error));
})
.then(function() {
isLoading = false;
var inp = el('mistralagent-input');
if (inp) { inp.disabled = false; inp.focus(); }
setButtonDisabled('mistralagent-send', false);
});
};
var startNewConversation = function() {
ajaxCall('block_mistralagent_new_conversation', {
blockinstanceid: blockInstanceId,
courseid:        courseId,
})
.then(function(response) {
if (response.success) {
conversationId = response.conversationid;
var list = el('mistralagent-conversations-list');
if (list) {
document.querySelectorAll('.mistralagent-conv-item')
.forEach(function(i) { i.classList.remove('active'); });
var item = document.createElement('div');
item.className = 'mistralagent-conv-item active';
item.dataset.convid = conversationId;
item.setAttribute('role', 'button');
item.setAttribute('tabindex', '0');
var titleEl = document.createElement('div');
titleEl.className   = 'conv-title';
titleEl.textContent = strings.newconversation || '';
item.appendChild(titleEl);
item.addEventListener('click', function() {
switchConversation(parseInt(item.dataset.convid, 10));
});
list.insertBefore(item, list.firstChild);
}
var container = el('mistralagent-messages');
if (container) { container.innerHTML = ''; }
var newUrl = new URL(window.location.href);
newUrl.searchParams.set('newconv', '1');
newUrl.searchParams.delete('convid');
history.pushState({}, '', newUrl.toString());
}
})
.catch(function(err) {
window.console.error('[MistralAgent] new_conversation error:', err);
});
};
var handleFileSelect = function(e) {
var file = e.target.files && e.target.files[0];
if (!file) { return; }
var ext = file.name.split('.').pop().toLowerCase();
setFileStatus(file.name, strings.extracting || '…', 'bg-info');
setHidden('mistralagent-file-preview', false);
if (ext === 'txt' || ext === 'json') {
var reader = new FileReader();
reader.onload = function(evt) {
attachedFileName    = file.name;
attachedFileContent = evt.target.result;
setFileStatus(file.name, (strings.fileready || '…') + ' (' + kbSize(attachedFileContent) + ')', 'bg-success');
};
reader.onerror = function() {
setFileStatus(file.name, strings.filefailed || '', 'bg-danger');
};
reader.readAsText(file);
return;
}
var formData = new FormData();
formData.append('userfile',        file);
formData.append('sesskey',         M.cfg.sesskey);
formData.append('blockinstanceid', blockInstanceId);
formData.append('courseid',        courseId);
fetch(M.cfg.wwwroot + '/blocks/mistralagent/extract_file_ajax.php', {
method: 'POST',
body:   formData,
})
.then(function(r) {
if (!r.ok) { throw new Error('HTTP ' + r.status); }
return r.json();
})
.then(function(resp) {
if (resp.success) {
attachedFileName    = file.name;
attachedFileContent = resp.text;
var isImage = resp.text.indexOf('__IMAGE_BASE64__') === 0;
if (isImage) {
setFileStatus(file.name, (strings.fileready || '…') + ' — image', 'bg-success');
} else if (resp.truncated) {
setFileStatus(file.name, (strings.fileready || '…') + ' (' + (strings.file_truncated || '…') + ', ' + kbSize(attachedFileContent) + ')', 'bg-warning');
} else {
setFileStatus(file.name, (strings.fileready || '…') + ' (' + kbSize(attachedFileContent) + ')', 'bg-success');
}
} else {
setFileStatus(file.name, strings.filefailed || '', 'bg-danger');
showError(resp.error || '');
}
})
.catch(function(err) {
setFileStatus(file.name, strings.filefailed || '', 'bg-danger');
showError('Erreur serveur : ' + (err && err.message ? err.message : err));
});
};
var removeFile = function() {
attachedFileName    = '';
attachedFileContent = '';
setHidden('mistralagent-file-preview', true);
setHidden('mistralagent-paste-btn', true);
var inp = el('mistralagent-file-input');
if (inp) { inp.value = ''; }
};
var openPasteModal = function() {
setHidden('mistralagent-paste-modal', false);
var area = el('mistralagent-paste-area');
if (area) { area.focus(); }
};
var closePasteModal = function() {
setHidden('mistralagent-paste-modal', true);
};
var confirmPastedText = function() {
var area = el('mistralagent-paste-area');
if (!area || !area.value.trim()) { closePasteModal(); return; }
attachedFileContent = area.value.trim();
area.value = '';
setFileStatus(
attachedFileName,
(strings.fileready || '…') + ' (' + kbSize(attachedFileContent) + ')',
'bg-success'
);
setHidden('mistralagent-paste-btn', true);
closePasteModal();
};
var toggleAgentBanner = function() {
var desc = el('mistralagent-agent-desc');
var btn  = el('mistralagent-banner-btn');
if (!desc) { return; }
var expanded = !desc.hidden;
desc.hidden = expanded;
if (btn) { btn.setAttribute('aria-expanded', String(!expanded)); }
};
var addMessageToDisplay = function(role, content, filename, images) {
var container = el('mistralagent-messages');
if (!container) { return; }
var wrapper = document.createElement('div');
wrapper.className = 'mistralagent-message ' + (role === 'user' ? 'user-message' : 'assistant-message');
if (filename && role === 'user') {
var fileTag = document.createElement('div');
fileTag.className   = 'message-file-tag';
fileTag.textContent = '📎 ' + filename;
wrapper.appendChild(fileTag);
}
var bubble = document.createElement('div');
bubble.className = 'message-bubble';
if (role === 'assistant') {
if (content) {
bubble.innerHTML = simpleMarkdown(content);
}
(images || []).forEach(function(url) {
var img = document.createElement('img');
img.src = url;
img.alt = strings.generated_image_alt || '';
img.style.maxWidth = '100%';
img.style.borderRadius = '0.5rem';
img.style.marginTop = '0.5rem';
img.style.display = 'block';
bubble.appendChild(img);
});
var copyBtn = document.createElement('button');
copyBtn.className   = 'btn btn-sm btn-outline-secondary copy-btn';
copyBtn.title       = strings.copy || '';
copyBtn.innerHTML   = '<i class="fa fa-copy" aria-hidden="true"></i>';
copyBtn.addEventListener('click', function() { copyToClipboard(content, copyBtn); });
wrapper.appendChild(bubble);
wrapper.appendChild(copyBtn);
} else {
bubble.textContent = content;
wrapper.appendChild(bubble);
}
container.appendChild(wrapper);
scrollToBottom();
};
var simpleMarkdown = function(text) {
return escapeHtml(text)
.replace(/```([\s\S]*?)```/g, '<pre><code>$1</code></pre>')
.replace(/`([^`]+)`/g, '<code>$1</code>')
.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
.replace(/\*(.+?)\*/g,     '<em>$1</em>')
.replace(/\n/g, '<br>');
};
var showTypingIndicator = function() {
var container = el('mistralagent-messages');
if (!container) { return; }
var wrapper = document.createElement('div');
wrapper.id        = 'mistralagent-typing-wrapper';
wrapper.className = 'mistralagent-message assistant-message';
var bubble = document.createElement('div');
bubble.className = 'message-bubble typing-indicator';
bubble.innerHTML = '<span></span><span></span><span></span>';
wrapper.appendChild(bubble);
container.appendChild(wrapper);
scrollToBottom();
};
var hideTypingIndicator = function() {
var w = document.getElementById('mistralagent-typing-wrapper');
if (w) { w.remove(); }
};
var updateQuotaDisplay = function(quota) {
var badge = el('mistralagent-quota');
if (!badge || !quota) { return; }
if (quota.unlimited) {
badge.textContent = strings.quotaunlimited || '∞';
badge.className   = 'badge bg-secondary ms-2';
} else if (quota.remaining !== null && quota.remaining !== undefined) {
badge.textContent = quota.remaining + ' / ' + quota.limit;
badge.className   = 'badge ms-2 ' + (quota.remaining > 5 ? 'bg-secondary' : (quota.remaining > 0 ? 'bg-warning' : 'bg-danger'));
}
};
var showError = function(msg) {
var container = el('mistralagent-messages');
if (!container) { return; }
var div = document.createElement('div');
div.className   = 'alert alert-danger mt-2';
div.setAttribute('role', 'alert');
div.textContent = msg;
container.appendChild(div);
scrollToBottom();
};
var buildFriendlyError = function(error) {
if (!error) { return strings.errorcommunication || ''; }
if (error.errorcode === 'invalidtoken') { return strings.sessexpired || ''; }
if (error.message && error.message.indexOf('cURL') !== -1) { return strings.errorcommunication || ''; }
var parts = [strings.errorcommunication || ''];
if (error.message)   { parts.push(error.message); }
if (error.errorcode) { parts.push('(' + error.errorcode + ')'); }
return parts.join(' — ');
};
var ajaxCall = function(methodname, args) {
return Ajax.call([{methodname: methodname, args: args}])[0];
};
var ajaxCallPost = function(methodname, args) {
var requests = JSON.stringify([{methodname: methodname, args: args}]);
return fetch(M.cfg.wwwroot + '/lib/ajax/service.php?sesskey=' + M.cfg.sesskey, {
method:  'POST',
headers: {'Content-Type': 'application/json'},
body:    requests,
}).then(function(r) {
if (!r.ok) { throw new Error('HTTP ' + r.status); }
return r.json();
}).then(function(data) {
if (!Array.isArray(data) || !data[0]) { throw new Error(strings.unexpected_server_response || ''); }
if (data[0].error) { throw new Error(data[0].exception ? (data[0].exception.message || JSON.stringify(data[0].exception)) : (strings.errorcommunication || '')); }
return data[0].data;
});
};
var el  = function(id) { return document.getElementById(id); };
var on  = function(id, ev, fn) { var e = el(id); if (e) { e.addEventListener(ev, fn); } };
var setButtonDisabled = function(id, d) { var b = el(id); if (b) { b.disabled = d; } };
var setHidden = function(id, h) { var e = el(id); if (e) { e.hidden = h; } };
var setFileStatus = function(name, status, cls) {
var n = el('mistralagent-file-name'), s = el('mistralagent-file-status');
if (n) { n.textContent = name; }
if (s) { s.textContent = status; s.className = 'badge ' + cls + ' ms-2'; }
};
var escapeHtml = function(text) {
var d = document.createElement('div');
d.textContent = text;
return d.innerHTML;
};
var kbSize       = function(str) { return Math.round(str.length / 1024) + ' Ko'; };
var scrollToBottom = function() { var c = el('mistralagent-messages'); if (c) { c.scrollTop = c.scrollHeight; } };
var copyToClipboard = function(text, button) {
navigator.clipboard.writeText(text).then(function() {
var orig = button.innerHTML;
button.innerHTML = '<i class="fa fa-check" aria-hidden="true"></i> ' + escapeHtml(strings.copied || '');
button.classList.add('copied');
setTimeout(function() { button.innerHTML = orig; button.classList.remove('copied'); }, 2000);
});
};
return { init: init };
});
